pub(crate) fn set_bundle_hive_project_state(
    output: &Path,
    enabled: bool,
    anchor: Option<&str>,
    joined_at: Option<DateTime<Utc>>,
) -> anyhow::Result<()> {
    let (config_path, mut config) = read_bundle_config_file(output)?;
    config.hive_project_enabled = enabled;
    config.hive_project_anchor = anchor
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    config.hive_project_joined_at = joined_at;
    write_bundle_config_file(&config_path, &config)?;

    rewrite_env_assignment(
        &output.join("env"),
        "MEMD_HIVE_PROJECT_ENABLED=",
        &format!(
            "MEMD_HIVE_PROJECT_ENABLED={}\n",
            if enabled { "true" } else { "false" }
        ),
    )?;
    rewrite_env_assignment(
        &output.join("env.ps1"),
        "$env:MEMD_HIVE_PROJECT_ENABLED = ",
        &format!(
            "$env:MEMD_HIVE_PROJECT_ENABLED = \"{}\"\n",
            if enabled { "true" } else { "false" }
        ),
    )?;

    if let Some(anchor) = config.hive_project_anchor.as_deref() {
        rewrite_env_assignment(
            &output.join("env"),
            "MEMD_HIVE_PROJECT_ANCHOR=",
            &format!("MEMD_HIVE_PROJECT_ANCHOR={anchor}\n"),
        )?;
        rewrite_env_assignment(
            &output.join("env.ps1"),
            "$env:MEMD_HIVE_PROJECT_ANCHOR = ",
            &format!(
                "$env:MEMD_HIVE_PROJECT_ANCHOR = \"{}\"\n",
                escape_ps1(anchor)
            ),
        )?;
    } else {
        remove_env_assignment(&output.join("env"), "MEMD_HIVE_PROJECT_ANCHOR=")?;
        remove_env_assignment(&output.join("env.ps1"), "$env:MEMD_HIVE_PROJECT_ANCHOR = ")?;
    }

    if let Some(joined_at) = config.hive_project_joined_at {
        let joined_at = joined_at.to_rfc3339();
        rewrite_env_assignment(
            &output.join("env"),
            "MEMD_HIVE_PROJECT_JOINED_AT=",
            &format!("MEMD_HIVE_PROJECT_JOINED_AT={joined_at}\n"),
        )?;
        rewrite_env_assignment(
            &output.join("env.ps1"),
            "$env:MEMD_HIVE_PROJECT_JOINED_AT = ",
            &format!(
                "$env:MEMD_HIVE_PROJECT_JOINED_AT = \"{}\"\n",
                escape_ps1(&joined_at)
            ),
        )?;
    } else {
        remove_env_assignment(&output.join("env"), "MEMD_HIVE_PROJECT_JOINED_AT=")?;
        remove_env_assignment(
            &output.join("env.ps1"),
            "$env:MEMD_HIVE_PROJECT_JOINED_AT = ",
        )?;
    }

    Ok(())
}

pub(crate) fn clear_bundle_hive_project_state(output: &Path) -> anyhow::Result<()> {
    set_bundle_hive_project_state(output, false, None, None)
}

pub(crate) fn rewrite_env_assignment(path: &Path, prefix: &str, replacement: &str) -> anyhow::Result<()> {
    let mut lines = if path.exists() {
        fs::read_to_string(path)
            .with_context(|| format!("read {}", path.display()))?
            .lines()
            .map(|line| format!("{line}\n"))
            .collect::<Vec<_>>()
    } else {
        Vec::new()
    };

    let mut replaced = false;
    for line in &mut lines {
        if line.starts_with(prefix) {
            *line = replacement.to_string();
            replaced = true;
        }
    }
    if !replaced {
        lines.push(replacement.to_string());
    }

    let mut output = String::new();
    for line in lines {
        output.push_str(&line);
    }
    fs::write(path, output).with_context(|| format!("write {}", path.display()))?;
    Ok(())
}

pub(crate) fn remove_env_assignment(path: &Path, prefix: &str) -> anyhow::Result<()> {
    if !path.exists() {
        return Ok(());
    }

    let content = fs::read_to_string(path).with_context(|| format!("read {}", path.display()))?;
    let mut output = String::new();
    for line in content.lines() {
        if !line.starts_with(prefix) {
            output.push_str(line);
            output.push('\n');
        }
    }

    fs::write(path, output).with_context(|| format!("write {}", path.display()))?;
    Ok(())
}


pub(crate) fn resolve_bundle_rag_config(config: BundleConfigFile) -> Option<BundleRagConfigState> {
    if let Some(rag) = config.backend.and_then(|backend| backend.rag) {
        let url = rag
            .url
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty());
        let enabled = rag.enabled.unwrap_or(url.is_some());
        let configured = url.is_some();
        return Some(BundleRagConfigState {
            configured,
            enabled,
            url,
            source: "backend.rag".to_string(),
        });
    }

    let url = config
        .rag_url
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    if let Some(url) = url {
        return Some(BundleRagConfigState {
            configured: true,
            enabled: true,
            url: Some(url),
            source: "rag_url".to_string(),
        });
    }

    None
}

pub(crate) fn escape_ps1(value: &str) -> String {
    value.replace('\"', "`\"")
}

pub(crate) fn compact_bundle_value(value: &str) -> String {
    value.split_whitespace().collect::<Vec<_>>().join(" ")
}

pub(crate) fn shell_single_quote(value: &str) -> String {
    format!("'{}'", value.replace('\'', "'\\''"))
}

pub(crate) fn memory_visibility_label(value: memd_schema::MemoryVisibility) -> &'static str {
    match value {
        memd_schema::MemoryVisibility::Private => "private",
        memd_schema::MemoryVisibility::Workspace => "workspace",
        memd_schema::MemoryVisibility::Public => "public",
    }
}

pub(crate) fn set_executable_if_shell_script(path: &Path, file_name: &str) -> anyhow::Result<()> {
    if !file_name.ends_with(".sh") {
        return Ok(());
    }

    #[cfg(unix)]
    {
        use std::os::unix::fs::PermissionsExt;

        let metadata = fs::metadata(path).with_context(|| format!("stat {}", path.display()))?;
        let mut permissions = metadata.permissions();
        permissions.set_mode(0o755);
        fs::set_permissions(path, permissions)
            .with_context(|| format!("chmod +x {}", path.display()))?;
    }

    Ok(())
}

